from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql

app = Flask(__name__)

def get_db_connection():
    conn = psycopg2.connect(
        dbname="yourdbname",
        user="yourdbuser",
        password="yourdbpassword",
        host="yourdbhost",
        port="yourdbport"
    )
    return conn

@app.route('/query', methods=['POST'])
def query_db():
    data = request.json
    table = data.get('table')
    columns = data.get('columns', '*')
    filters = data.get('filters', {})

    if not table or not isinstance(columns, list):
        return jsonify({"error": "Invalid input"}), 400

    try:
        conn = get_db_connection()
        cur = conn.cursor()

        query = sql.SQL("SELECT {fields} FROM {table}").format(
            fields=sql.SQL(', ').join(map(sql.Identifier, columns)),
            table=sql.Identifier(table)
        )

        if filters:
            filter_clauses = []
            filter_values = []
            for col, val in filters.items():
                filter_clauses.append(sql.SQL("{} = %s").format(sql.Identifier(col)))
                filter_values.append(val)
            query += sql.SQL(" WHERE ") + sql.SQL(" AND ").join(filter_clauses)

        cur.execute(query, filter_values)
        rows = cur.fetchall()
        cur.close()
        conn.close()

        return jsonify(rows)

    except Exception as e:
        return jsonify({"error": str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)